use crate::model::common::Language;

pub const PROTOBUF_HEADER: &str = "Generated by the protocol buffer compiler.  DO NOT EDIT!";
pub const THRIFT_HEADER: &str = "Autogenerated by Thrift Compiler";

/// Max number of characters we use at the file header to detect if this is a generated file.
pub const MAX_HEADER_SIZE: usize = 400;

/// Returns if a file is generated or not based on a few heuristics.
/// Some heuristics are based on these sources
///  - https://github.com/github-linguist/linguist/blob/master/lib/linguist/generated.rb
///
/// We only look at the first few bytes of the code that are generally comments generated by
/// code generation tools. We look at most at [MAX_HEADER_SIZE] characters.
pub fn is_generated_file(full_content: &str, language: &Language) -> bool {
    let size_to_analyze = MAX_HEADER_SIZE.min(full_content.len());

    let content = &full_content.get(0..size_to_analyze).unwrap_or(full_content);
    match language {
        Language::Go => {
            content.contains("Code generated by")
                | content.contains(PROTOBUF_HEADER)
                | content.contains(THRIFT_HEADER)
        }
        Language::Java => {
            content.contains("generated by the protocol buffer compiler")
                | content.contains("@javax.annotation.Generated")
                | content.contains("This file is generated by")
                | content.contains("This class was generated by")
                | content.contains("by ANTLR")
                | content.contains(PROTOBUF_HEADER)
                | content.contains(THRIFT_HEADER)
        }
        Language::JavaScript => {
            content.contains("Generated by PEG.js")
                | content.contains("GENERATED CODE -- DO NOT EDIT!")
                | content.contains("@generated by")
                | content.contains("Auto-generated by")
                | content.contains(THRIFT_HEADER)
        }
        Language::Python => {
            content.contains("Generated protocol buffer code")
                | content.contains("Generated by the gRPC Python protocol compiler plugin")
                | content.contains("Code generated by")
                | content.contains("file was automatically generated by")
                | content.contains("Automatically generated by Colab")
                | content.contains(PROTOBUF_HEADER)
                | content.contains(THRIFT_HEADER)
        }
        Language::Ruby => {
            content.contains("# Code generated by")
                | content.contains("This file is auto-generated from the current")
                | content.contains(PROTOBUF_HEADER)
                | content.contains(THRIFT_HEADER)
        }
        Language::TypeScript => {
            content.contains("Generated by PEG.js")
                | content.contains("GENERATED CODE -- DO NOT EDIT!")
                | content.contains("@generated by")
                | content.contains("auto-generated by")
                | content.contains(THRIFT_HEADER)
        }
        Language::Csharp => {
            content.contains("<autogenerated") | content.contains("<auto-generated")
        }
        Language::Dart => {
            content.contains("GENERATED CODE - DO NOT MODIFY")
                | content.contains("This is a generated file")
                | content.contains("Generated code. Do not modify")
        }
        _ => false,
    }
}

/// Returns if a file is minified or not.
/// The heuristic for detecting minified files is based on the average line length being greater
/// than 110.
pub fn is_minified_file(content: &str, language: &Language) -> bool {
    if language == &Language::JavaScript {
        content
            .len()
            .checked_div(content.lines().count())
            .is_some_and(|avg| avg > 110)
    } else {
        false
    }
}

/// Glob patterns that are, by default, excluded from analysis. These patterns are for paths
/// that often contain either vendored 3rd party dependencies or generated files.
pub const DEFAULT_IGNORED_GLOBS: &[&str] = &[
    // JavaScript
    "**/node_modules/**/*",
    "**/jspm_packages/**/*",
    "**/.next/**/*",
    "**/.vuepress/**/*",
    // Python
    "**/venv/**/*",
    "**/__pycache__/**/*",
    // Ruby
    "**/_vendor/bundle/ruby/**/*",
    "**/.vendor/bundle/ruby/**/*",
    "**/.bundle/**/*",
    // Java
    "**/.gradle/**/*",
    // C#
    "**/TemporaryGeneratedFile_.*.cs",
    "**/*.designer.cs",
    "**/*.generated.cs",
    "**/*.g.cs",
    "**/*.g.i.cs",
];

#[cfg(test)]
mod tests {
    use crate::analysis::generated_content::{
        is_generated_file, is_minified_file, PROTOBUF_HEADER, THRIFT_HEADER,
    };
    use crate::model::common::Language;

    #[test]
    fn test_is_generated_file_java() {
        assert!(!is_generated_file(&"class Foobar", &Language::Java));
        assert!(is_generated_file(
            &"// generated by the protocol buffer compiler\n class Foobar{}",
            &Language::Java
        ));
        assert!(is_generated_file(
            &format!("// {}\n class Foobar{{}}", PROTOBUF_HEADER),
            &Language::Java
        ));
        assert!(is_generated_file(
            &format!("// {}\n class Foobar{{}}", THRIFT_HEADER),
            &Language::Java
        ));
        assert!(is_generated_file(
            "@javax.annotation.Generated(value = \"org.openapitools.codegen.languages.JavaClientCodegen\")\nclass Foo {}",
            &Language::Java
        ));
        assert!(is_generated_file(
            "/*\n * This file is generated by jOOQ.\n */\nclass Foo {}",
            &Language::Java
        ));
        assert!(is_generated_file(
            "/**\n * This class was generated by the JAX-WS RI.\n */\nclass Foo {}",
            &Language::Java
        ));
        assert!(is_generated_file(
            "// Generated from MyParser.g4 by ANTLR 4.13.1\nclass Foo {}",
            &Language::Java
        ));
    }

    #[test]
    fn test_is_generated_file_go() {
        assert!(!is_generated_file(&"fn func(){}", &Language::Go));
        assert!(is_generated_file(
            &"// Code generated by MockGen\nfn func(){}",
            &Language::Go
        ));
        assert!(is_generated_file(
            &format!("// {}\nfn func(){{}}", PROTOBUF_HEADER),
            &Language::Go
        ));
        assert!(is_generated_file(
            &format!("// {}\nfn func(){{}}", THRIFT_HEADER),
            &Language::Go
        ));
    }

    #[test]
    fn test_is_generated_file_python() {
        assert!(!is_generated_file(
            &"def foo():\n  pass\n",
            &Language::Python
        ));
        assert!(is_generated_file(
            &"# Code generated by some tool\ndef foo():\n  pass\n",
            &Language::Go
        ));
        assert!(is_generated_file(
            &format!("# {}\ndef foo():\n  pass\n", THRIFT_HEADER),
            &Language::Go
        ));
        assert!(is_generated_file(
            &format!("# {}\ndef foo():\n  pass\n", PROTOBUF_HEADER),
            &Language::Go
        ));
        assert!(is_generated_file(
            "# This file was automatically generated by SWIG (https://www.swig.org).\ndef foo():\n  pass\n",
            &Language::Python
        ));
        assert!(is_generated_file(
            "# Automatically generated by Colab.\ndef foo():\n  pass\n",
            &Language::Python
        ));
    }

    #[test]
    fn test_is_generated_file_dart() {
        assert!(is_generated_file(
            "// GENERATED CODE - DO NOT MODIFY BY HAND\n\npart of 'foo.dart';\n",
            &Language::Dart
        ));
        assert!(is_generated_file(
            "// This is a generated file - do not edit.\n//\n// Generated from foo.proto.\n\n// @dart = 3.3\n",
            &Language::Dart
        ));
        assert!(is_generated_file(
            "//\n//  Generated code. Do not modify.\n//  source:foo.proto\n\n// @dart = 2.3",
            &Language::Dart
        ));
        assert!(!is_generated_file(
            "void main() {\n  print('hello');\n}\n",
            &Language::Dart
        ));
    }

    #[test]
    fn test_is_generated_file_ruby() {
        assert!(is_generated_file(
            &format!("# {}\ndef foo():\n  pass\n", THRIFT_HEADER),
            &Language::Ruby
        ));
        assert!(is_generated_file(
            &format!("# {}\ndef foo():\n  pass\n", PROTOBUF_HEADER),
            &Language::Ruby
        ));
        assert!(is_generated_file(
            "# Code generated by Speakeasy (https://speakeasy.com). DO NOT EDIT.\nmodule Foo; end\n",
            &Language::Ruby
        ));
        // Rails db/schema.rb
        assert!(is_generated_file(
            "# This file is auto-generated from the current state of the database.\nActiveRecord::Schema.define(...)\n",
            &Language::Ruby
        ));
    }

    #[test]
    fn test_is_generated_file_javascript() {
        assert!(!is_generated_file(
            &"function smtg(){}",
            &Language::JavaScript
        ));
        assert!(is_generated_file(
            &"// GENERATED CODE -- DO NOT EDIT!\nfunction smtg(){}",
            &Language::JavaScript
        ));
        assert!(is_generated_file(
            &"// Generated by PEG.js\nfunction smtg(){}",
            &Language::JavaScript
        ));
        assert!(is_generated_file(
            &format!("// {}\nfunction smtg(){{}}", THRIFT_HEADER),
            &Language::JavaScript
        ));
        assert!(is_generated_file(
            "// @generated by protoc-gen-es v2.7.0\nfunction smtg(){}",
            &Language::JavaScript
        ));
        assert!(is_generated_file(
            "/*\nAuto-generated by: https://github.com/pmndrs/gltfjsx\n*/\nfunction smtg(){}",
            &Language::JavaScript
        ));
    }

    #[test]
    fn test_is_generated_file_typescript() {
        assert!(!is_generated_file(
            &"function smtg(){}",
            &Language::TypeScript
        ));
        assert!(is_generated_file(
            &"// GENERATED CODE -- DO NOT EDIT!\nfunction smtg(){}",
            &Language::TypeScript
        ));
        assert!(is_generated_file(
            &"// Generated by PEG.js\nfunction smtg(){}",
            &Language::TypeScript
        ));
        assert!(is_generated_file(
            &format!("// {}\nfunction smtg(){{}}", THRIFT_HEADER),
            &Language::TypeScript
        ));
        assert!(is_generated_file(
            "// @generated by protobuf-ts 2.9.1\nexport const x = 1;\n",
            &Language::TypeScript
        ));
        assert!(is_generated_file(
            "/**\n * This file was auto-generated by openapi-typescript.\n */\nexport const x = 1;\n",
            &Language::TypeScript
        ));
    }

    #[test]
    fn test_is_generated_file_csharp() {
        assert!(!is_generated_file(
            &"// <notautogenerated>\nfunction smtg(){}",
            &Language::Csharp,
        ));
        assert!(is_generated_file(
            &"// <autogenerated>\nfunction smtg(){}",
            &Language::Csharp
        ));
        assert!(is_generated_file(
            &"//----\n  <auto-generated>\n  Autogenerated\n  </auto-generated>\n//----\nfunction smtg(){}",
            &Language::Csharp
        ));
    }

    #[test]
    fn test_is_minified_file_javascript() {
        assert!(is_minified_file(
            &"var x = 2;".repeat(100),
            &Language::JavaScript
        ));
    }
}
